CREATE EXTENSION IF NOT EXISTS vector;
CREATE TABLE IF NOT EXISTS users (id SERIAL PRIMARY KEY, wecom_userid VARCHAR(128) UNIQUE, name VARCHAR(255), avatar_url VARCHAR(500), mobile VARCHAR(32), email VARCHAR(255), department_ids INTEGER[], created_at TIMESTAMP DEFAULT NOW(), updated_at TIMESTAMP DEFAULT NOW());
CREATE TABLE IF NOT EXISTS sessions (id SERIAL PRIMARY KEY, user_id INTEGER REFERENCES users(id) ON DELETE SET NULL, session_id VARCHAR(128) UNIQUE, status VARCHAR(32) DEFAULT 'active', agent_id INTEGER, created_at TIMESTAMP DEFAULT NOW(), closed_at TIMESTAMP, last_message_at TIMESTAMP DEFAULT NOW());
CREATE TABLE IF NOT EXISTS messages (id SERIAL PRIMARY KEY, session_id INTEGER REFERENCES sessions(id) ON DELETE CASCADE, message_id VARCHAR(128) UNIQUE, msg_type VARCHAR(32), content TEXT, media_id VARCHAR(255), sender_type VARCHAR(32), sender_id VARCHAR(128), ai_model_used VARCHAR(128), token_count INTEGER, created_at TIMESTAMP DEFAULT NOW());
CREATE TABLE IF NOT EXISTS agents (id SERIAL PRIMARY KEY, agent_id VARCHAR(128) UNIQUE, name VARCHAR(255), email VARCHAR(255), password_hash VARCHAR(255), role VARCHAR(32) DEFAULT 'agent', is_online BOOLEAN DEFAULT FALSE, max_concurrent INTEGER DEFAULT 5, current_concurrent INTEGER DEFAULT 0, created_at TIMESTAMP DEFAULT NOW(), updated_at TIMESTAMP DEFAULT NOW());
CREATE TABLE IF NOT EXISTS knowledge_base (id SERIAL PRIMARY KEY, name VARCHAR(255), description TEXT, file_name VARCHAR(500), file_path VARCHAR(500), file_type VARCHAR(32), file_size INTEGER, status VARCHAR(32) DEFAULT 'processing', chunk_count INTEGER DEFAULT 0, created_at TIMESTAMP DEFAULT NOW(), updated_at TIMESTAMP DEFAULT NOW());
CREATE TABLE IF NOT EXISTS kb_chunks (id SERIAL PRIMARY KEY, kb_id INTEGER REFERENCES knowledge_base(id) ON DELETE CASCADE, chunk_index INTEGER, content TEXT, token_count INTEGER, created_at TIMESTAMP DEFAULT NOW());
CREATE TABLE IF NOT EXISTS kb_embeddings (id SERIAL PRIMARY KEY, chunk_id INTEGER REFERENCES kb_chunks(id) ON DELETE CASCADE, embedding vector(1536), created_at TIMESTAMP DEFAULT NOW());
CREATE TABLE IF NOT EXISTS configs (id SERIAL PRIMARY KEY, config_key VARCHAR(255) UNIQUE, config_value TEXT, description TEXT, updated_at TIMESTAMP DEFAULT NOW());
CREATE INDEX IF NOT EXISTS idx_sessions_user_id ON sessions(user_id);
